import React, { useEffect, useRef, useCallback } from "react";
import "./Skills.css";
import "./SkillsDeck.css";
import SoftwareSkill from "../../components/softwareSkills/SoftwareSkill";
import { skills } from "../../portfolio";
import DataScienceImg from "./DataScienceImg";
import FullStackImg from "./FullStackImg";
import CloudInfraImg from "./CloudInfraImg";

function GetSkillSvg(props) {
  if (props.fileName === "DataScienceImg")
    return <DataScienceImg theme={props.theme} />;
  else if (props.fileName === "FullStackImg")
    return <FullStackImg theme={props.theme} />;
  else if (props.fileName === "CloudInfraImg")
    return <CloudInfraImg theme={props.theme} />;
  return null;
}

/* Per-card accent + kicker; order matches skills.data in portfolio.js */
const CARD_META = [
  { accent: "#4AD8FF", accentSoft: "rgba(74, 216, 255, 0.14)", kicker: "01 · Engineering" },
  { accent: "#8A6BFF", accentSoft: "rgba(138, 107, 255, 0.14)", kicker: "02 · Intelligence" },
  { accent: "#FF7F50", accentSoft: "rgba(255, 127, 80, 0.14)", kicker: "03 · Scale" },
];

const prefersReducedMotion = () =>
  typeof window !== "undefined" &&
  window.matchMedia("(prefers-reduced-motion: reduce)").matches;

export default function Skills(props) {
  const theme = props.theme;
  const headerRef = useRef(null);
  const itemRefs = useRef([]);

  /* Entry reveal: snappy staggered fade-up once a card reaches the viewport */
  useEffect(() => {
    const io = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.classList.add("deck-in");
            io.unobserve(entry.target);
          }
        });
      },
      { threshold: 0.2, rootMargin: "0px 0px -8% 0px" }
    );
    if (headerRef.current) io.observe(headerRef.current);
    itemRefs.current.forEach((el) => el && io.observe(el));
    return () => io.disconnect();
  }, []);

  /* Stack effect: as the next card slides over, the pinned card recedes.
     Drives --cover (0 → 1) per card; CSS maps it to scale / lift / dimming. */
  useEffect(() => {
    if (prefersReducedMotion()) return;
    let rafId = null;

    const update = () => {
      rafId = null;
      if (window.innerWidth < 769) return;
      const vh = window.innerHeight || 1;
      const pinTop = vh * 0.12;
      const items = itemRefs.current;
      for (let i = 0; i < items.length - 1; i++) {
        const card = items[i] && items[i].firstElementChild;
        const next = items[i + 1];
        if (!card || !next) continue;
        const nextTop = next.getBoundingClientRect().top;
        // Start reacting while the next card is still just below the fold
        // (1.08vh) so there is never a scroll range with zero motion.
        const cover = Math.min(
          Math.max((vh * 1.08 - nextTop) / (vh * 1.08 - pinTop), 0),
          1
        );
        card.style.setProperty("--cover", cover.toFixed(3));
      }
    };

    const onScroll = () => {
      if (!rafId) rafId = requestAnimationFrame(update);
    };

    update();
    window.addEventListener("scroll", onScroll, { passive: true });
    window.addEventListener("resize", onScroll, { passive: true });
    return () => {
      window.removeEventListener("scroll", onScroll);
      window.removeEventListener("resize", onScroll);
      if (rafId) cancelAnimationFrame(rafId);
    };
  }, []);

  /* Cursor tilt + spotlight that follows the mouse across the card */
  const handleTilt = useCallback((e) => {
    if (prefersReducedMotion() || window.innerWidth < 769) return;
    const el = e.currentTarget;
    const r = el.getBoundingClientRect();
    const x = (e.clientX - r.left) / r.width;
    const y = (e.clientY - r.top) / r.height;
    el.style.setProperty("--ry", `${(x - 0.5) * 3.5}deg`);
    el.style.setProperty("--rx", `${(0.5 - y) * 2.5}deg`);
    el.style.setProperty("--mx", `${(x * 100).toFixed(1)}%`);
    el.style.setProperty("--my", `${(y * 100).toFixed(1)}%`);
  }, []);

  const resetTilt = useCallback((e) => {
    const el = e.currentTarget;
    el.style.setProperty("--rx", "0deg");
    el.style.setProperty("--ry", "0deg");
  }, []);

  return (
    <section
      className="skills-deck-section"
      id="skills"
      data-theme={theme.name}
      style={{
        "--deck-text": theme.text,
        "--deck-secondary": theme.secondaryText,
      }}
    >
      <div className="deck-header" ref={headerRef}>
        <span className="deck-kicker">My Expertise</span>
        <h1 className="deck-title" style={{ color: theme.text }}>
          Here's what I do
        </h1>
        <p className="deck-subtitle" style={{ color: theme.secondaryText }}>
          Three domains. One goal — intelligent products that ship.
        </p>
      </div>

      <div className="skills-deck">
        {skills.data.map((skill, i) => {
          const meta = CARD_META[i % CARD_META.length];
          return (
            <div
              className="deck-item"
              key={skill.title}
              ref={(el) => (itemRefs.current[i] = el)}
              style={{ "--i": i }}
            >
              <article
                className={`deck-card ${i % 2 ? "deck-card-flip" : ""}`}
                onMouseMove={handleTilt}
                onMouseLeave={resetTilt}
                style={{
                  "--card-accent": meta.accent,
                  "--card-accent-soft": meta.accentSoft,
                }}
              >
                <div className="deck-card-spotlight" aria-hidden="true" />
                <span className="deck-card-index" aria-hidden="true">
                  {String(i + 1).padStart(2, "0")}
                </span>

                <div className="deck-card-content">
                  <div className="deck-text-col">
                    <span className="deck-card-kicker">{meta.kicker}</span>
                    <h2 className="deck-card-title" style={{ color: theme.text }}>
                      {skill.title}
                    </h2>
                    <div className="deck-card-logos">
                      <SoftwareSkill logos={skill.softwareSkills} />
                    </div>
                    <div className="deck-bullets">
                      {skill.skills.map((sentence) => (
                        <p
                          key={sentence}
                          className="deck-bullet"
                          style={{ color: theme.secondaryText }}
                        >
                          {sentence}
                        </p>
                      ))}
                    </div>
                  </div>
                  <div className="deck-art-col">
                    <div className="deck-art-glow" aria-hidden="true" />
                    <GetSkillSvg fileName={skill.fileName} theme={theme} />
                  </div>
                </div>
              </article>
            </div>
          );
        })}
      </div>
    </section>
  );
}
